12995   /// Calculate the cost of a reduction.
12996   InstructionCost getReductionCost(TargetTransformInfo *TTI,
12997                                    ArrayRef<Value *> ReducedVals,
12998                                    unsigned ReduxWidth, FastMathFlags FMF) {
12999     TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
13000     Value *FirstReducedVal = ReducedVals.front();
13001     Type *ScalarTy = FirstReducedVal->getType();
13002     FixedVectorType *VectorTy = FixedVectorType::get(ScalarTy, ReduxWidth);
13003     InstructionCost VectorCost = 0, ScalarCost;
13004     // If all of the reduced values are constant, the vector cost is 0, since
13005     // the reduction value can be calculated at the compile time.
13006     bool AllConsts = allConstant(ReducedVals);
13007     switch (RdxKind) {
13008     case RecurKind::Add:
13009     case RecurKind::Mul:
13010     case RecurKind::Or:
13011     case RecurKind::And:
13012     case RecurKind::Xor:
13013     case RecurKind::FAdd:
13014     case RecurKind::FMul: {
13015       unsigned RdxOpcode = RecurrenceDescriptor::getOpcode(RdxKind);
13016       if (!AllConsts)
13017         VectorCost =
13018             TTI->getArithmeticReductionCost(RdxOpcode, VectorTy, FMF, CostKind);
13019       ScalarCost = TTI->getArithmeticInstrCost(RdxOpcode, ScalarTy, CostKind);
13020       break;
13021     }
13022     case RecurKind::FMax:
13023     case RecurKind::FMin: {
13024       auto *SclCondTy = CmpInst::makeCmpResultType(ScalarTy);
13025       if (!AllConsts) {
13026         auto *VecCondTy =
13027             cast<VectorType>(CmpInst::makeCmpResultType(VectorTy));
13028         VectorCost =
13029             TTI->getMinMaxReductionCost(VectorTy, VecCondTy,
13030                                         /*IsUnsigned=*/false, CostKind);
13031       }
13032       CmpInst::Predicate RdxPred = getMinMaxReductionPredicate(RdxKind);
13033       ScalarCost = TTI->getCmpSelInstrCost(Instruction::FCmp, ScalarTy,
13034                                            SclCondTy, RdxPred, CostKind) +
13035                    TTI->getCmpSelInstrCost(Instruction::Select, ScalarTy,
13036                                            SclCondTy, RdxPred, CostKind);
13037       break;
13038     }
13039     case RecurKind::SMax:
13040     case RecurKind::SMin:
13041     case RecurKind::UMax:
13042     case RecurKind::UMin: {
13043       auto *SclCondTy = CmpInst::makeCmpResultType(ScalarTy);
13044       if (!AllConsts) {
13045         auto *VecCondTy =
13046             cast<VectorType>(CmpInst::makeCmpResultType(VectorTy));
13047         bool IsUnsigned =
13048             RdxKind == RecurKind::UMax || RdxKind == RecurKind::UMin;
13049         VectorCost = TTI->getMinMaxReductionCost(VectorTy, VecCondTy,
13050                                                  IsUnsigned, CostKind);
13051       }
13052       CmpInst::Predicate RdxPred = getMinMaxReductionPredicate(RdxKind);
13053       ScalarCost = TTI->getCmpSelInstrCost(Instruction::ICmp, ScalarTy,
13054                                            SclCondTy, RdxPred, CostKind) +
13055                    TTI->getCmpSelInstrCost(Instruction::Select, ScalarTy,
13056                                            SclCondTy, RdxPred, CostKind);
13057       break;
13058     }
13059     default:
13060       llvm_unreachable("Expected arithmetic or min/max reduction operation");
13061     }
13062 
13063     // Scalar cost is repeated for N-1 elements.
13064     ScalarCost *= (ReduxWidth - 1);
13065     LLVM_DEBUG(dbgs() << "SLP: Adding cost " << VectorCost - ScalarCost
13066                       << " for reduction that starts with " << *FirstReducedVal
13067                       << " (It is a splitting reduction)\n");
13068     return VectorCost - ScalarCost;
13069   }
