13227   unsigned AggregateSize = 1;
13228   auto *IV = cast<InsertValueInst>(InsertInst);
13229   Type *CurrentType = IV->getType();
13230   do {
13231     if (auto *ST = dyn_cast<StructType>(CurrentType)) {
13232       for (auto *Elt : ST->elements())
13233         if (Elt != ST->getElementType(0)) // check homogeneity
13234           return std::nullopt;
13235       AggregateSize *= ST->getNumElements();
13236       CurrentType = ST->getElementType(0);
13237     } else if (auto *AT = dyn_cast<ArrayType>(CurrentType)) {
13238       AggregateSize *= AT->getNumElements();
13239       CurrentType = AT->getElementType();
13240     } else if (auto *VT = dyn_cast<FixedVectorType>(CurrentType)) {
13241       AggregateSize *= VT->getNumElements();
13242       return AggregateSize;
13243     } else if (CurrentType->isSingleValueType()) {
13244       return AggregateSize;
13245     } else {
13246       return std::nullopt;
13247     }
13248   } while (true);
