12608           VectorizedTree = GetNewVectorizedTree(VectorizedTree, RedVal);
12609           VectorizedVals.try_emplace(OrigV, Cnt);
12610           continue;
12611         }
12612       }
12613 
12614       unsigned MaxVecRegSize = V.getMaxVecRegSize();
12615       unsigned EltSize = V.getVectorElementSize(Candidates[0]);
12616       unsigned MaxElts =
12617           RegMaxNumber * llvm::bit_floor(MaxVecRegSize / EltSize);
12618 
12619       unsigned ReduxWidth = std::min<unsigned>(
12620           llvm::bit_floor(NumReducedVals), std::max(RedValsMaxNumber, MaxElts));
12621       unsigned Start = 0;
12622       unsigned Pos = Start;
12623       // Restarts vectorization attempt with lower vector factor.
12624       unsigned PrevReduxWidth = ReduxWidth;
12625       bool CheckForReusedReductionOpsLocal = false;
12626       auto &&AdjustReducedVals = [&Pos, &Start, &ReduxWidth, NumReducedVals,
12627                                   &CheckForReusedReductionOpsLocal,
12628                                   &PrevReduxWidth, &V,
12629                                   &IgnoreList](bool IgnoreVL = false) {
12630         bool IsAnyRedOpGathered = !IgnoreVL && V.isAnyGathered(IgnoreList);
12631         if (!CheckForReusedReductionOpsLocal && PrevReduxWidth == ReduxWidth) {
12632           // Check if any of the reduction ops are gathered. If so, worth
12633           // trying again with less number of reduction ops.
12634           CheckForReusedReductionOpsLocal |= IsAnyRedOpGathered;
12635         }
12636         ++Pos;
12637         if (Pos < NumReducedVals - ReduxWidth + 1)
12638           return IsAnyRedOpGathered;
12639         Pos = Start;
12640         ReduxWidth /= 2;
12641         return IsAnyRedOpGathered;
12642       };
12643       bool AnyVectorized = false;
12644       while (Pos < NumReducedVals - ReduxWidth + 1 &&
12645              ReduxWidth >= ReductionLimit) {
12646         // Dependency in tree of the reduction ops - drop this attempt, try
12647         // later.
12648         if (CheckForReusedReductionOpsLocal && PrevReduxWidth != ReduxWidth &&
12649             Start == 0) {
12650           CheckForReusedReductionOps = true;
12651           break;
12652         }
12653         PrevReduxWidth = ReduxWidth;
12654         ArrayRef<Value *> VL(std::next(Candidates.begin(), Pos), ReduxWidth);
12655         // Beeing analyzed already - skip.
12656         if (V.areAnalyzedReductionVals(VL)) {
12657           (void)AdjustReducedVals(/*IgnoreVL=*/true);
12658           continue;
12659         }
12660         // Early exit if any of the reduction values were deleted during
12661         // previous vectorization attempts.
12662         if (any_of(VL, [&V](Value *RedVal) {
12663               auto *RedValI = dyn_cast<Instruction>(RedVal);
12664               if (!RedValI)
12665                 return false;
12666               return V.isDeleted(RedValI);
12667             }))
12668           break;
12669         V.buildTree(VL, IgnoreList);
12670         if (V.isTreeTinyAndNotFullyVectorizable(/*ForReduction=*/true)) {
12671           if (!AdjustReducedVals())
12672             V.analyzedReductionVals(VL);
12673           continue;
12674         }
12675         if (V.isLoadCombineReductionCandidate(RdxKind)) {
12676           if (!AdjustReducedVals())
12677             V.analyzedReductionVals(VL);
12678           continue;
12679         }
12680         V.reorderTopToBottom();
12681         // No need to reorder the root node at all.
12682         V.reorderBottomToTop(/*IgnoreReorder=*/true);
12683         // Keep extracted other reduction values, if they are used in the
12684         // vectorization trees.
12685         BoUpSLP::ExtraValueToDebugLocsMap LocalExternallyUsedValues(
12686             ExternallyUsedValues);
12687         for (unsigned Cnt = 0, Sz = ReducedVals.size(); Cnt < Sz; ++Cnt) {
12688           if (Cnt == I || (ShuffledExtracts && Cnt == I - 1))
12689             continue;
12690           for_each(ReducedVals[Cnt],
12691                    [&LocalExternallyUsedValues, &TrackedVals](Value *V) {
12692                      if (isa<Instruction>(V))
12693                        LocalExternallyUsedValues[TrackedVals[V]];
12694                    });
12695         }
12696         if (!IsSupportedHorRdxIdentityOp) {
12697           // Number of uses of the candidates in the vector of values.
12698           assert(SameValuesCounter.empty() &&
12699                  "Reused values counter map is not empty");
12700           for (unsigned Cnt = 0; Cnt < NumReducedVals; ++Cnt) {
12701             if (Cnt >= Pos && Cnt < Pos + ReduxWidth)
12702               continue;
12703             Value *V = Candidates[Cnt];
12704             Value *OrigV = TrackedToOrig.find(V)->second;
12705             ++SameValuesCounter[OrigV];
12706           }
12707         }
12708         SmallPtrSet<Value *, 4> VLScalars(VL.begin(), VL.end());
12709         // Gather externally used values.
12710         SmallPtrSet<Value *, 4> Visited;
12711         for (unsigned Cnt = 0; Cnt < NumReducedVals; ++Cnt) {
12712           if (Cnt >= Pos && Cnt < Pos + ReduxWidth)
12713             continue;
12714           Value *RdxVal = Candidates[Cnt];
12715           if (!Visited.insert(RdxVal).second)
12716             continue;
12717           // Check if the scalar was vectorized as part of the vectorization
12718           // tree but not the top node.
12719           if (!VLScalars.contains(RdxVal) && V.isVectorized(RdxVal)) {
12720             LocalExternallyUsedValues[RdxVal];
12721             continue;
12722           }
12723           Value *OrigV = TrackedToOrig.find(RdxVal)->second;
12724           unsigned NumOps =
12725               VectorizedVals.lookup(RdxVal) + SameValuesCounter[OrigV];
12726           if (NumOps != ReducedValsToOps.find(RdxVal)->second.size())
12727             LocalExternallyUsedValues[RdxVal];
12728         }
12729         // Do not need the list of reused scalars in regular mode anymore.
12730         if (!IsSupportedHorRdxIdentityOp)
12731           SameValuesCounter.clear();
12732         for (Value *RdxVal : VL)
12733           if (RequiredExtract.contains(RdxVal))
12734             LocalExternallyUsedValues[RdxVal];
12735         V.buildExternalUses(LocalExternallyUsedValues);
12736 
12737         V.computeMinimumValueSizes();
12738 
12739         // Intersect the fast-math-flags from all reduction operations.
12740         FastMathFlags RdxFMF;
12741         RdxFMF.set();
12742         for (Value *U : IgnoreList)
12743           if (auto *FPMO = dyn_cast<FPMathOperator>(U))
12744             RdxFMF &= FPMO->getFastMathFlags();
12745         // Estimate cost.
12746         InstructionCost TreeCost = V.getTreeCost(VL);
12747         InstructionCost ReductionCost =
12748             getReductionCost(TTI, VL, ReduxWidth, RdxFMF);
12749         if (V.isVectorizedFirstNode() && isa<LoadInst>(VL.front())) {
12750           Instruction *MainOp = V.getFirstNodeMainOp();
12751           for (Value *V : VL) {
12752             auto *VI = dyn_cast<LoadInst>(V);
12753             // Add the costs of scalar GEP pointers, to be removed from the
12754             // code.
12755             if (!VI || VI == MainOp)
12756               continue;
12757             auto *Ptr = dyn_cast<GetElementPtrInst>(VI->getPointerOperand());
12758             if (!Ptr || !Ptr->hasOneUse() || Ptr->hasAllConstantIndices())
12759               continue;
12760             TreeCost -= TTI->getArithmeticInstrCost(
12761                 Instruction::Add, Ptr->getType(), TTI::TCK_RecipThroughput);
12762           }
12763         }
12764         InstructionCost Cost = TreeCost + ReductionCost;
12765         LLVM_DEBUG(dbgs() << "SLP: Found cost = " << Cost << " for reduction\n");
12766         if (!Cost.isValid())
12767           return nullptr;
12768         if (Cost >= -SLPCostThreshold) {
12769           V.getORE()->emit([&]() {
12770             return OptimizationRemarkMissed(
12771                        SV_NAME, "HorSLPNotBeneficial",
12772                        ReducedValsToOps.find(VL[0])->second.front())
12773                    << "Vectorizing horizontal reduction is possible "
12774                    << "but not beneficial with cost " << ore::NV("Cost", Cost)
12775                    << " and threshold "
12776                    << ore::NV("Threshold", -SLPCostThreshold);
12777           });
12778           if (!AdjustReducedVals())
12779             V.analyzedReductionVals(VL);
12780           continue;
12781         }
12782 
12783         LLVM_DEBUG(dbgs() << "SLP: Vectorizing horizontal reduction at cost:"
12784                           << Cost << ". (HorRdx)\n");
12785         V.getORE()->emit([&]() {
12786           return OptimizationRemark(
12787                      SV_NAME, "VectorizedHorizontalReduction",
12788                      ReducedValsToOps.find(VL[0])->second.front())
12789                  << "Vectorized horizontal reduction with cost "
12790                  << ore::NV("Cost", Cost) << " and with tree size "
12791                  << ore::NV("TreeSize", V.getTreeSize());
12792         });
12793 
12794         Builder.setFastMathFlags(RdxFMF);
12795 
12796         // Emit a reduction. If the root is a select (min/max idiom), the insert
12797         // point is the compare condition of that select.
12798         Instruction *RdxRootInst = cast<Instruction>(ReductionRoot);
12799         Instruction *InsertPt = RdxRootInst;
12800         if (IsCmpSelMinMax)
12801           InsertPt = GetCmpForMinMaxReduction(RdxRootInst);
12802 
12803         // Vectorize a tree.
12804         Value *VectorizedRoot =
12805             V.vectorizeTree(LocalExternallyUsedValues, InsertPt);
12806 
12807         Builder.SetInsertPoint(InsertPt);
